     1|/**
     2| * IVX Data-Loss Prevention Guard.
     3| *
     4| * After the 2026-07-06 incident where an autonomous "cleanup" phase wiped
     5| * visitor analytics + real member records from Supabase, this guard was
     6| * created to ensure that can NEVER happen again.
     7| *
     8| * The guard intercepts any destructive operation (DELETE, TRUNCATE, DROP,
     9| * mass row removal) targeting production tables and:
    10| *   1. Requires explicit owner approval with a written reason.
    11| *   2. Takes a vault snapshot BEFORE the operation proceeds.
    12| *   3. Logs the operation to an immutable audit trail.
    13| *   4. Refuses if the operation targets a protected table without a special
    14| *      "emergency" flag.
    15| *
    16| * Protected tables (can NEVER be bulk-deleted by autonomous systems):
    17| *   - members, waitlist, waitlist_entries
    18| *   - investors, buyers
    19| *   - landing_analytics, analytics_events, visitor_sessions
    20| *   - jv_deals, wallets, ledger, treasury
    21| *   - landing_submissions, landing_investments
    22| *   - profiles, kyc_verifications
    23| *
    24| * @module ivx-data-loss-guard
    25| */
    26|
    27|import { promises as fs } from 'node:fs';
    28|import path from 'node:path';
    29|import { runDataVaultSnapshot, type SnapshotReport } from './ivx-data-vault';
    30|
    31|export const IVX_DATA_LOSS_GUARD_MARKER = 'ivx-data-loss-guard-2026-07-06';
    32|
    33|const AUDIT_TRAIL_FILE = path.resolve(process.cwd(), 'logs', 'audit', 'data-vault', 'destructive-ops-audit.jsonl');
    34|
    35|/**
    36| * Tables that are PROTECTED from autonomous bulk deletion. A human owner
    37| * can still run a restore or migration, but the autonomous AI / night-ops /
    38| * senior-developer / cleanup scripts can NEVER bulk-delete from these.
    39| */
    40|export const PROTECTED_TABLES: ReadonlySet<string> = new Set([
    41|  'members',
    42|  'waitlist',
    43|  'waitlist_entries',
    44|  'investors',
    45|  'buyers',
    46|  'crm_investors',
    47|  'crm_buyers',
    48|  'landing_analytics',
    49|  'analytics_events',
    50|  'visitor_sessions',
    51|  'landing_submissions',
    52|  'landing_investments',
    53|  'jv_deals',
    54|  'wallets',
    55|  'wallet_transactions',
    56|  'treasury',
    57|  'ledger',
    58|  'withdrawals',
    59|  'wire_transfers',
    60|  'private_lenders',
    61|  'tokenized_investments',
    62|  'profiles',
    63|  'kyc_verifications',
    64|  'kyc_documents',
    65|  'earn_accounts',
    66|  'earn_deposits',
    67|  'earn_payouts',
    68|  'referrals',
    69|  'referral_invites',
    70|  'ipx_holdings',
    71|  'ipx_purchases',
    72|]);
    73|
    74|/**
    75| * Patterns that indicate a destructive operation. If a SQL string or command
    76| * matches any of these, it is intercepted by the guard.
    77| */
    78|const DESTRUCTIVE_PATTERNS: RegExp[] = [
    79|  /\bDELETE\s+FROM\b/i,
    80|  /\bTRUNCATE\b/i,
    81|  /\bDROP\s+TABLE\b/i,
    82|  /\bDROP\s+SCHEMA\b/i,
    83|  /rm\s+-rf/i,
    84|  /\bwipe\b/i,
    85|  /\bpurge\b/i,
    86|  /\btruncate\s+table\b/i,
    87|];
    88|
    89|export type DestructiveOpRequest = {
    90|  /** The SQL or command being evaluated. */
    91|  operation: string;
    92|  /** The table(s) that would be affected, if known. */
    93|  tables: string[];
    94|  /** Whether this is an autonomous system (vs a human owner). */
    95|  isAutonomous: boolean;
    96|  /** Whether the owner has explicitly approved with a reason. */
    97|  ownerApproved: boolean;
    98|  /** The owner's written reason for the operation (required if ownerApproved). */
    99|  ownerReason: string | null;
   100|  /** Whether this is an emergency (e.g. GDPR data deletion request). */
   101|  emergency: boolean;
   102|};
   103|
   104|export type DestructiveOpDecision = {
   105|  allowed: boolean;
   106|  blocker: string | null;
   107|  snapshotTaken: SnapshotReport | null;
   108|  auditEntry: DestructiveOpAuditEntry;
   109|};
   110|
   111|export type DestructiveOpAuditEntry = {
   112|  timestamp: string;
   113|  operation: string;
   114|  tables: string[];
   115|  isAutonomous: boolean;
   116|  ownerApproved: boolean;
   117|  ownerReason: string | null;
   118|  emergency: boolean;
   119|  allowed: boolean;
   120|  blocker: string | null;
   121|  snapshotId: string | null;
   122|  marker: string;
   123|};
   124|
   125|/**
   126| * Detect whether a string contains a destructive SQL/command pattern.
   127| * Pure function — deterministic, no side effects.
   128| */
   129|export function isDestructiveOperation(input: string): boolean {
   130|  if (!input || typeof input !== 'string') return false;
   131|  return DESTRUCTIVE_PATTERNS.some((p) => p.test(input));
   132|}
   133|
   134|/**
   135| * Extract table names from a destructive SQL string. Best-effort regex
   136| * extraction — not a full SQL parser. Returns lowercased table names.
   137| * Pure function — deterministic.
   138| */
   139|export function extractTableNames(sql: string): string[] {
   140|  if (!sql || typeof sql !== 'string') return [];
   141|  const tables = new Set<string>();
   142|
   143|  // DELETE FROM <table>
   144|  let m: RegExpExecArray | null;
   145|  const deleteRe = /\bDELETE\s+FROM\s+(?:public\.)?([a-z_][a-z0-9_]*)/gi;
   146|  while ((m = deleteRe.exec(sql)) !== null) tables.add(m[1].toLowerCase());
   147|
   148|  // TRUNCATE [TABLE] <table>[, <table2>...]
   149|  const truncateRe = /\bTRUNCATE\s+(?:TABLE\s+)?(?:public\.)?([a-z_][a-z0-9_,\s.]*)/gi;
   150|  while ((m = truncateRe.exec(sql)) !== null) {
   151|    for (const part of m[1].split(',')) {
   152|      const name = part.trim().replace(/^public\./, '').toLowerCase();
   153|      if (name) tables.add(name);
   154|    }
   155|  }
   156|
   157|  // DROP TABLE <table>
   158|  const dropRe = /\bDROP\s+TABLE\s+(?:IF\s+EXISTS\s+)?(?:public\.)?([a-z_][a-z0-9_]*)/gi;
   159|  while ((m = dropRe.exec(sql)) !== null) tables.add(m[1].toLowerCase());
   160|
   161|  return Array.from(tables);
   162|}
   163|
   164|/**
   165| * Evaluate a destructive operation request. Decides whether it is allowed,
   166| * takes a pre-snapshot if it is, and writes the audit entry.
   167| */
   168|export async function evaluateDestructiveOp(request: DestructiveOpRequest): Promise<DestructiveOpDecision> {
   169|  const timestamp = new Date().toISOString();
   170|  const tables = request.tables.length > 0 ? request.tables : extractTableNames(request.operation);
   171|
   172|  let blocker: string | null = null;
   173|
   174|  // Rule 1: Autonomous systems can NEVER run destructive ops on protected tables.
   175|  if (request.isAutonomous) {
   176|    const protectedHit = tables.find((t) => PROTECTED_TABLES.has(t.toLowerCase()));
   177|    if (protectedHit) {
   178|      blocker = `BLOCKED: Autonomous systems cannot run destructive operations on protected table "${protectedHit}". This guard was added after the 2026-07-06 data-loss incident. An owner must run this manually with explicit approval.`;
   179|    }
   180|  }
   181|
   182|  // Rule 2: Even for a human owner, destructive ops require explicit approval + reason.
   183|  if (!blocker && !request.ownerApproved) {
   184|    blocker = 'BLOCKED: Destructive operation requires explicit owner approval. Pass ownerApproved: true and provide a written reason.';
   185|  }
   186|
   187|  if (!blocker && request.ownerApproved && !request.ownerReason) {
   188|    blocker = 'BLOCKED: Owner-approved destructive operation requires a written reason explaining why the data is being deleted.';
   189|  }
   190|
   191|  // Rule 3: Non-emergency destructive ops on protected tables require a snapshot first.
   192|  let snapshotTaken: SnapshotReport | null = null;
   193|  if (!blocker) {
   194|    const protectedHit = tables.find((t) => PROTECTED_TABLES.has(t.toLowerCase()));
   195|    if (protectedHit && !request.emergency) {
   196|      try {
   197|        snapshotTaken = await runDataVaultSnapshot();
   198|      } catch (err) {
   199|        blocker = `BLOCKED: Pre-destruction snapshot failed (cannot safely proceed without a backup): ${err instanceof Error ? err.message : 'unknown error'}`;
   200|      }
   201|    }
   202|  }
   203|
   204|  const allowed = blocker === null;
   205|
   206|  const auditEntry: DestructiveOpAuditEntry = {
   207|    timestamp,
   208|    operation: request.operation.slice(0, 2000),
   209|    tables,
   210|    isAutonomous: request.isAutonomous,
   211|    ownerApproved: request.ownerApproved,
   212|    ownerReason: request.ownerReason,
   213|    emergency: request.emergency,
   214|    allowed,
   215|    blocker,
   216|    snapshotId: snapshotTaken?.snapshotId ?? null,
   217|    marker: IVX_DATA_LOSS_GUARD_MARKER,
   218|  };
   219|
   220|  // Write to immutable audit trail
   221|  await appendDestructiveOpAudit(auditEntry);
   222|
   223|  if (allowed) {
   224|    console.log(`[IVXDataLossGuard] ALLOWED destructive op on [${tables.join(', ')}] — snapshot ${snapshotTaken?.snapshotId ?? 'none'} taken`);
   225|  } else {
   226|    console.warn(`[IVXDataLossGuard] ${blocker}`);
   227|  }
   228|
   229|  return { allowed, blocker, snapshotTaken, auditEntry };
   230|}
   231|
   232|async function appendDestructiveOpAudit(entry: DestructiveOpAuditEntry): Promise<void> {
   233|  try {
   234|    const dir = path.dirname(AUDIT_TRAIL_FILE);
   235|    await fs.mkdir(dir, { recursive: true });
   236|    await fs.appendFile(AUDIT_TRAIL_FILE, JSON.stringify(entry) + '\n', 'utf8');
   237|  } catch {
   238|    // never let audit writing block the decision
   239|  }
   240|}
   241|
   242|export async function readDestructiveOpAudit(limit: number = 100): Promise<DestructiveOpAuditEntry[]> {
   243|  try {
   244|    const text = await fs.readFile(AUDIT_TRAIL_FILE, 'utf8');
   245|    const lines = text.trim().split('\n').filter(Boolean);
   246|    return lines
   247|      .slice(-limit)
   248|      .map((line) => {
   249|        try {
   250|          return JSON.parse(line) as DestructiveOpAuditEntry;
   251|        } catch {
   252|          return null;
   253|        }
   254|      })
   255|      .filter((e): e is DestructiveOpAuditEntry => e !== null)
   256|      .reverse(); // newest first
   257|  } catch {
   258|    return [];
   259|  }
   260|}

