     1|/**
     2| * IVX Data Vault — independent backup & recovery system.
     3| *
     4| * The IVX Data Vault snapshots critical Supabase tables to the backend's own
     5| * filesystem (our "own data center") on a schedule, so that if Supabase loses
     6| * data — a bad migration, a cleanup script, a dropped table, a PITR gap — every
     7| * row can be restored from the vault.
     8| *
     9| * Design principles:
    10| *   1. INDEPENDENT — the vault lives on the backend's disk, NOT in Supabase.
    11| *      A Supabase outage or data loss event cannot destroy the vault.
    12| *   2. APPEND-ONLY — snapshots are never overwritten or auto-deleted. Each
    13| *      snapshot is a timestamped JSON file. Retention is configurable but the
    14| *      default keeps ALL snapshots (we have disk space; we do not have a
    15| *      second chance at lost data).
    16| *   3. CRYPTOGRAPHIC INTEGRITY — every snapshot is SHA-256 hashed and the hash
    17| *      is recorded in an append-only manifest. A tampered snapshot is detected.
    18| *   4. OWNER-GATED RESTORE — restoring overwrites production, so it always
    19| *      requires explicit owner approval via the API.
    20| *   5. HONEST — if a table is empty or missing, the snapshot records that
    21| *      honestly. The vault never fabricates data.
    22| *
    23| * Storage layout:
    24| *   logs/audit/data-vault/
    25| *     manifest.jsonl          — append-only ledger of every snapshot
    26| *     state.json              — scheduler state (last run, next run, config)
    27| *     snapshots/
    28| *       <snapshotId>/
    29| *         meta.json           — snapshot metadata + per-table hashes
    30| *         members.json
    31| *         waitlist.json
    32| *         investors.json
    33| *         buyers.json
    34| *         landing_analytics.json
    35| *         analytics_events.json
    36| *         visitor_sessions.json
    37| *         jv_deals.json
    38| *         ... (all critical tables)
    39| *
    40| * Scheduled by a background timer (every 6 hours by default). Can also be
    41| * triggered manually via the owner API.
    42| *
    43| * @module ivx-data-vault
    44| */
    45|
    46|import { promises as fs } from 'node:fs';
    47|import path from 'node:path';
    48|import { createHash } from 'node:crypto';
    49|
    50|export const IVX_DATA_VAULT_MARKER = 'ivx-data-vault-2026-07-06';
    51|
    52|const VAULT_DIR = path.resolve(process.cwd(), 'logs', 'audit', 'data-vault');
    53|const SNAPSHOTS_DIR = path.join(VAULT_DIR, 'snapshots');
    54|const MANIFEST_FILE = path.join(VAULT_DIR, 'manifest.jsonl');
    55|const STATE_FILE = path.join(VAULT_DIR, 'state.json');
    56|
    57|// ---------------------------------------------------------------------------
    58|// Config & state
    59|// ---------------------------------------------------------------------------
    60|
    61|export type DataVaultConfig = {
    62|  /** Interval between automatic snapshots, in milliseconds. Default 6h. */
    63|  intervalMs: number;
    64|  /** Whether the automatic scheduler is enabled. */
    65|  enabled: boolean;
    66|  /** Max snapshots to retain (0 = keep ALL forever). */
    67|  maxSnapshots: number;
    68|  /** Tables to snapshot on every run. */
    69|  tables: string[];
    70|};
    71|
    72|export type DataVaultState = {
    73|  marker: string;
    74|  config: DataVaultConfig;
    75|  lastSnapshotAt: string | null;
    76|  lastSnapshotId: string | null;
    77|  totalSnapshots: number;
    78|  nextScheduledRun: string | null;
    79|};
    80|
    81|const DEFAULT_TABLES = [
    82|  'members',
    83|  'waitlist',
    84|  'waitlist_entries',
    85|  'investors',
    86|  'buyers',
    87|  'jv_deals',
    88|  'private_lenders',
    89|  'tokenized_investments',
    90|  'wallets',
    91|  'wallet_transactions',
    92|  'treasury',
    93|  'ledger',
    94|  'withdrawals',
    95|  'wire_transfers',
    96|  'notifications',
    97|  'landing_analytics',
    98|  'analytics_events',
    99|  'visitor_sessions',
   100|  'landing_submissions',
   101|  'landing_investments',
   102|  'profiles',
   103|  'kyc_verifications',
   104|  'referrals',
   105|  'earn_accounts',
   106|  'earn_deposits',
   107|  'earn_payouts',
   108|];
   109|
   110|const DEFAULT_CONFIG: DataVaultConfig = {
   111|  intervalMs: 6 * 60 * 60 * 1000, // 6 hours
   112|  enabled: true,
   113|  maxSnapshots: 0, // keep ALL forever
   114|  tables: DEFAULT_TABLES,
   115|};
   116|
   117|// ---------------------------------------------------------------------------
   118|// Supabase config resolver
   119|// ---------------------------------------------------------------------------
   120|
   121|type SupabaseConfig = { url: string; key: string; missing: string[] };
   122|
   123|function resolveSupabase(): SupabaseConfig {
   124|  const url = (process.env.EXPO_PUBLIC_SUPABASE_URL || '').trim().replace(/\/+$/, '');
   125|  const key = (process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.SUPABASE_SERVICE_KEY || '').trim();
   126|  const missing: string[] = [];
   127|  if (!url) missing.push('EXPO_PUBLIC_SUPABASE_URL');
   128|  if (!key) missing.push('SUPABASE_SERVICE_ROLE_KEY');
   129|  return { url, key, missing };
   130|}
   131|
   132|// ---------------------------------------------------------------------------
   133|// Table snapshot helpers
   134|// ---------------------------------------------------------------------------
   135|
   136|type TableSnapshotResult = {
   137|  table: string;
   138|  ok: boolean;
   139|  rowCount: number;
   140|  /** SHA-256 of the serialized JSON rows. */
   141|  hash: string | null;
   142|  /** Number of bytes on disk. */
   143|  bytes: number;
   144|  status: number;
   145|  error: string | null;
   146|  /** ISO timestamp. */
   147|  capturedAt: string;
   148|};
   149|
   150|async function fetchAllRows(
   151|  baseUrl: string,
   152|  key: string,
   153|  table: string,
   154|): Promise<{ rows: unknown[]; status: number; error: string | null }> {
   155|  const headers = {
   156|    apikey: key,
   157|    Authorization: `Bearer ${key}`,
   158|    Accept: 'application/json',
   159|  };
   160|
   161|  try {
   162|    // Fetch up to 50,000 rows per table. For visitor analytics tables that
   163|    // could have 27k+ events, we page with Range headers.
   164|    const allRows: unknown[] = [];
   165|    let offset = 0;
   166|    const pageSize = 1000;
   167|    const maxPages = 50; // 50,000 rows max
   168|
   169|    for (let page = 0; page < maxPages; page++) {
   170|      const controller = new AbortController();
   171|      const timeout = setTimeout(() => controller.abort(), 15_000);
   172|      try {
   173|        const res = await fetch(
   174|          `${baseUrl}/rest/v1/${table}?select=*&order=id.asc&limit=${pageSize}&offset=${offset}`,
   175|          {
   176|            method: 'GET',
   177|            signal: controller.signal,
   178|            headers: {
   179|              ...headers,
   180|              Range: `${offset}-${offset + pageSize - 1}`,
   181|              Prefer: 'count=exact',
   182|            },
   183|          },
   184|        );
   185|        clearTimeout(timeout);
   186|
   187|        if (res.status === 404) {
   188|          return { rows: [], status: 404, error: 'TABLE_NOT_FOUND' };
   189|        }
   190|        if (!res.ok) {
   191|          return { rows: [], status: res.status, error: `HTTP_${res.status}` };
   192|        }
   193|
   194|        const rows = (await res.json()) as unknown[];
   195|        allRows.push(...rows);
   196|
   197|        // If we got fewer rows than the page size, we've reached the end.
   198|        if (rows.length < pageSize) break;
   199|        offset += pageSize;
   200|      } catch (err) {
   201|        clearTimeout(timeout);
   202|        throw err;
   203|      }
   204|    }
   205|
   206|    return { rows: allRows, status: 200, error: null };
   207|  } catch (err) {
   208|    return {
   209|      rows: [],
   210|      status: 0,
   211|      error: err instanceof Error ? err.message : 'network_error',
   212|    };
   213|  }
   214|}
   215|
   216|function sha256OfJson(data: unknown): string {
   217|  const json = JSON.stringify(data);
   218|  return createHash('sha256').update(json).digest('hex');
   219|}
   220|
   221|async function snapshotOneTable(
   222|  baseUrl: string,
   223|  key: string,
   224|  table: string,
   225|  snapshotDir: string,
   226|): Promise<TableSnapshotResult> {
   227|  const capturedAt = new Date().toISOString();
   228|  const result = await fetchAllRows(baseUrl, key, table);
   229|
   230|  if (result.error === 'TABLE_NOT_FOUND') {
   231|    return {
   232|      table,
   233|      ok: false,
   234|      rowCount: 0,
   235|      hash: null,
   236|      bytes: 0,
   237|      status: 404,
   238|      error: 'TABLE_NOT_FOUND',
   239|      capturedAt,
   240|    };
   241|  }
   242|
   243|  if (result.error) {
   244|    return {
   245|      table,
   246|      ok: false,
   247|      rowCount: 0,
   248|      hash: null,
   249|      bytes: 0,
   250|      status: result.status,
   251|      error: result.error,
   252|      capturedAt,
   253|    };
   254|  }
   255|
   256|  // Write the rows to disk.
   257|  const json = JSON.stringify(result.rows, null, 2);
   258|  const hash = createHash('sha256').update(json).digest('hex');
   259|  const filePath = path.join(snapshotDir, `${table}.json`);
   260|
   261|  try {
   262|    await fs.writeFile(filePath, json, 'utf8');
   263|  } catch (err) {
   264|    return {
   265|      table,
   266|      ok: false,
   267|      rowCount: result.rows.length,
   268|      hash,
   269|      bytes: json.length,
   270|      status: 200,
   271|      error: `write_failed: ${err instanceof Error ? err.message : 'unknown'}`,
   272|      capturedAt,
   273|    };
   274|  }
   275|
   276|  return {
   277|    table,
   278|    ok: true,
   279|    rowCount: result.rows.length,
   280|    hash,
   281|    bytes: json.length,
   282|    status: 200,
   283|    error: null,
   284|    capturedAt,
   285|  };
   286|}
   287|
   288|// ---------------------------------------------------------------------------
   289|// Manifest (append-only ledger)
   290|// ---------------------------------------------------------------------------
   291|
   292|export type ManifestEntry = {
   293|  snapshotId: string;
   294|  timestamp: string;
   295|  tableCount: number;
   296|  totalRows: number;
   297|  totalBytes: number;
   298|  tables: { table: string; rowCount: number; hash: string | null; ok: boolean; error: string | null }[];
   299|  marker: string;
   300|};
   301|
   302|async function appendManifest(entry: ManifestEntry): Promise<void> {
   303|  await ensureVaultDirs();
   304|  try {
   305|    await fs.appendFile(MANIFEST_FILE, JSON.stringify(entry) + '\n', 'utf8');
   306|  } catch {
   307|    // never let manifest failure block a snapshot
   308|  }
   309|}
   310|
   311|export async function readManifest(limit: number = 100): Promise<ManifestEntry[]> {
   312|  try {
   313|    const text = await fs.readFile(MANIFEST_FILE, 'utf8');
   314|    const lines = text.trim().split('\n').filter(Boolean);
   315|    return lines
   316|      .slice(-limit)
   317|      .map((line) => {
   318|        try {
   319|          return JSON.parse(line) as ManifestEntry;
   320|        } catch {
   321|          return null;
   322|        }
   323|      })
   324|      .filter((e): e is ManifestEntry => e !== null)
   325|      .reverse(); // newest first
   326|  } catch {
   327|    return [];
   328|  }
   329|}
   330|
   331|// ---------------------------------------------------------------------------
   332|// State I/O
   333|// ---------------------------------------------------------------------------
   334|
   335|async function ensureVaultDirs(): Promise<void> {
   336|  await fs.mkdir(VAULT_DIR, { recursive: true }).catch(() => {});
   337|  await fs.mkdir(SNAPSHOTS_DIR, { recursive: true }).catch(() => {});
   338|}
   339|
   340|async function readState(): Promise<DataVaultState> {
   341|  try {
   342|    const text = await fs.readFile(STATE_FILE, 'utf8');
