   676|      ok: false,
   677|      tablesRestored: 0,
   678|      totalRowsRestored: 0,
   679|      tables: [],
   680|      durationMs: Date.now() - startedAt,
   681|      timestamp,
   682|      requiresOwnerApproval: true,
   683|    };
   684|  }
   685|
   686|  const snapshot = await readSnapshot(snapshotId);
   687|  if (!snapshot) {
   688|    return {
   689|      snapshotId,
   690|      ok: false,
   691|      tablesRestored: 0,
   692|      totalRowsRestored: 0,
   693|      tables: [],
   694|      durationMs: Date.now() - startedAt,
   695|      timestamp,
   696|      requiresOwnerApproval: true,
   697|    };
   698|  }
   699|
   700|  const tablesToRestore = options.tables ?? snapshot.tables.filter((t) => t.ok && t.rowCount > 0).map((t) => t.table);
