   818|      severity: 'none',
   819|      tablesAffected: [],
   820|      lastSnapshotId: state.lastSnapshotId,
   821|      lastSnapshotAt: state.lastSnapshotAt,
   822|      checkedAt,
   823|    };
   824|  }
   825|
   826|  const headers = {
